//! Dyn-compatible adapter layer over the RPITIT ISB traits.
//!
//! `ISBReader`/`ISBWriter` (generated by `trait_variant`) are not dyn-compatible
//! because their async methods return `impl Future`. These twin traits box the
//! futures so the rest of the pipeline can hold type-erased `Arc<dyn ...>` handles,
//! while backend implementations keep writing plain `async fn`s against the
//! statically-dispatched traits. The blanket impls below bridge the two worlds.

use std::time::Duration;

use futures::future::BoxFuture;

use crate::Result;
use crate::message::{Message, NackOptions, Offset};

use super::{ISBReader, ISBWriter, PendingWrite, WriteError, WriteResult};

/// Type-erased, shareable ISB reader handle.
pub(crate) type ISBReaderRef = std::sync::Arc<dyn DynISBReader>;
/// Type-erased, shareable ISB writer handle.
pub(crate) type ISBWriterRef = std::sync::Arc<dyn DynISBWriter>;

/// Dyn-compatible twin of [`ISBReader`]. Do not implement this directly —
/// implement [`LocalISBReader`]/[`ISBReader`] and rely on the blanket impl.
pub(crate) trait DynISBReader: Send + Sync {
    fn fetch<'a>(
        &'a self,
        max: usize,
        timeout: Duration,
    ) -> BoxFuture<'a, Result<Vec<Message>>>;
    fn ack<'a>(&'a self, offset: &'a Offset) -> BoxFuture<'a, Result<()>>;
    fn nack<'a>(
        &'a self,
        offset: &'a Offset,
        nack_options: Option<NackOptions>,
    ) -> BoxFuture<'a, Result<()>>;
    fn pending<'a>(&'a self) -> BoxFuture<'a, Result<Option<usize>>>;
    fn name(&self) -> &'static str;
    fn mark_wip<'a>(&'a self, offset: &'a Offset) -> BoxFuture<'a, Result<()>>;
    fn wip_ack_interval(&self) -> Option<Duration>;
}

impl<T: ISBReader> DynISBReader for T {
    fn fetch<'a>(
        &'a self,
        max: usize,
        timeout: Duration,
    ) -> BoxFuture<'a, Result<Vec<Message>>> {
        Box::pin(ISBReader::fetch(self, max, timeout))
    }
    fn ack<'a>(&'a self, offset: &'a Offset) -> BoxFuture<'a, Result<()>> {
        Box::pin(ISBReader::ack(self, offset))
    }
    fn nack<'a>(
        &'a self,
        offset: &'a Offset,
        nack_options: Option<NackOptions>,
    ) -> BoxFuture<'a, Result<()>> {
        Box::pin(ISBReader::nack(self, offset, nack_options))
    }
    fn pending<'a>(&'a self) -> BoxFuture<'a, Result<Option<usize>>> {
        Box::pin(ISBReader::pending(self))
    }
    fn name(&self) -> &'static str {
        ISBReader::name(self)
    }
    fn mark_wip<'a>(&'a self, offset: &'a Offset) -> BoxFuture<'a, Result<()>> {
        Box::pin(ISBReader::mark_wip(self, offset))
    }
    fn wip_ack_interval(&self) -> Option<Duration> {
        ISBReader::wip_ack_interval(self)
    }
}

/// Dyn-compatible twin of [`ISBWriter`]. Implement [`LocalISBWriter`] instead.
pub(crate) trait DynISBWriter: Send + Sync {
    fn async_write<'a>(
        &'a self,
        message: Message,
    ) -> BoxFuture<'a, std::result::Result<PendingWrite, WriteError>>;
    fn write<'a>(
        &'a self,
        message: Message,
    ) -> BoxFuture<'a, std::result::Result<WriteResult, WriteError>>;
    #[allow(dead_code)] // part of the ISBWriter surface; used by backends/tests
    fn name(&self) -> &'static str;
    #[allow(dead_code)] // part of the ISBWriter surface; used by backends/tests
    fn is_full(&self) -> bool;
}

impl<T: ISBWriter> DynISBWriter for T {
    fn async_write<'a>(
        &'a self,
        message: Message,
    ) -> BoxFuture<'a, std::result::Result<PendingWrite, WriteError>> {
        Box::pin(ISBWriter::async_write(self, message))
    }
    fn write<'a>(
        &'a self,
        message: Message,
    ) -> BoxFuture<'a, std::result::Result<WriteResult, WriteError>> {
        Box::pin(ISBWriter::write(self, message))
    }
    fn name(&self) -> &'static str {
        ISBWriter::name(self)
    }
    fn is_full(&self) -> bool {
        ISBWriter::is_full(self)
    }
}
